public class CustomAuthorizationCodeServices implements AuthorizationCodeServices {

    private final Map<String, AuthorizationRequest> authorizationCodes = new ConcurrentHashMap<>();
    private static final long EXPIRATION_TIME = 10 * 60 * 1000; // 10 minutes

    @Override
    public String create(AuthorizationRequest authorizationRequest) {
        String code = generateAuthorizationCode();
        authorizationCodes.put(code, authorizationRequest);
        scheduleExpiration(code);
        return code;
    }

    @Override
    public AuthorizationRequest consume(String authorizationCode) {
        return authorizationCodes.remove(authorizationCode);
    }

    private String generateAuthorizationCode() {
        // Generate a unique code (this is just an example)
        return java.util.UUID.randomUUID().toString();
    }

    private void scheduleExpiration(final String code) {
        new Thread(() -> {
            try {
                Thread.sleep(EXPIRATION_TIME);
                authorizationCodes.remove(code);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }).start();
    }
}